import { useState } from 'react';
import { Check, ChevronLeft, ChevronRight } from 'lucide-react';

export function ReUIStepper() {
  const [currentStep, setCurrentStep] = useState(1);
  const steps = [
    { id: 1, title: "Account Details", desc: "Set username and security password" },
    { id: 2, title: "Personal Profile", desc: "Tell us about your organization" },
    { id: 3, title: "Confirm Details", desc: "Review and deploy config" },
  ];

  const handleNext = () => {
    if (currentStep < steps.length) {
      setCurrentStep((prev) => prev + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  };

  return (
    <div className="w-full max-w-3xl mx-auto border border-border bg-card text-card-foreground p-6 rounded-2xl shadow-xl">
      {/* Stepper Header Grid */}
      <div className="grid grid-cols-3 gap-4 mb-8">
        {steps.map((step) => {
          const isCompleted = currentStep > step.id;
          const isActive = currentStep === step.id;
          return (
            <div key={step.id} className="flex flex-col gap-2 relative">
              <div className="flex items-center gap-3">
                <div 
                  className={`flex h-8 w-8 items-center justify-center rounded-full border text-xs font-bold transition-all duration-300 ${
                    isCompleted
                      ? 'bg-emerald-500 border-emerald-500 text-white'
                      : isActive
                      ? 'bg-primary border-primary text-primary-foreground shadow-md ring-4 ring-primary/20'
                      : 'bg-muted border-border text-muted-foreground'
                  }`}
                >
                  {isCompleted ? <Check className="h-4.5 w-4.5" /> : step.id}
                </div>
                <span className={`text-sm font-semibold truncate hidden md:inline ${
                  isActive ? 'text-foreground' : 'text-muted-foreground'
                }`}>
                  {step.title}
                </span>
              </div>
              <div 
                className={`h-1.5 rounded-full bg-muted overflow-hidden mt-1`}
              >
                <div 
                  style={{ width: isCompleted ? '100%' : isActive ? '50%' : '0%' }}
                  className="h-full bg-primary transition-all duration-500 ease-in-out"
                />
              </div>
            </div>
          );
        })}
      </div>

      {/* Active Panel Content Box */}
      <div className="min-h-48 border border-dashed border-border rounded-xl p-6 flex flex-col justify-center bg-muted/20 transition-all duration-300">
        <h3 className="text-lg font-bold tracking-tight text-foreground mb-1">
          {steps[currentStep - 1].title}
        </h3>
        <p className="text-sm text-muted-foreground mb-6">
          {steps[currentStep - 1].desc}
        </p>

        <div className="text-sm border border-border/60 bg-muted/40 p-4 rounded-lg text-foreground font-mono">
          {currentStep === 1 && <p>root@openblocks:~$ enter username & email...</p>}
          {currentStep === 2 && <p>root@openblocks:~$ enter location & bio details...</p>}
          {currentStep === 3 && <p>root@openblocks:~$ deploy openblocks-server --init</p>}
        </div>
      </div>

      {/* Navigation Buttons */}
      <div className="flex items-center justify-between border-t border-border mt-6 pt-4">
        <button
          onClick={handleBack}
          disabled={currentStep === 1}
          className="inline-flex items-center gap-2 px-4 py-2 text-sm font-medium border border-border rounded-lg bg-background hover:bg-muted text-foreground transition-colors disabled:opacity-50 disabled:pointer-events-none"
        >
          <ChevronLeft className="h-4 w-4" />
          <span>Back</span>
        </button>

        <button
          onClick={handleNext}
          disabled={currentStep === steps.length}
          className="inline-flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg bg-primary hover:bg-primary/95 text-primary-foreground transition-colors disabled:opacity-50 disabled:pointer-events-none"
        >
          <span>Continue</span>
          <ChevronRight className="h-4 w-4" />
        </button>
      </div>
    </div>
  );
}

