import { useEffect, useState } from 'react';

export function TextGenerateEffect({
  words = "Make your developer interfaces look stunning and interactive with openblocks.",
  className = ""
}) {
  const [visibleCount, setVisibleCount] = useState(0);
  const wordsArray = words.split(" ");

  useEffect(() => {
    const timer = setInterval(() => {
      setVisibleCount((prev) => {
        if (prev < wordsArray.length) {
          return prev + 1;
        }
        clearInterval(timer);
        return prev;
      });
    }, 150);

    return () => clearInterval(timer);
  }, [wordsArray.length]);

  return (
    <div className={`font-bold tracking-tight text-3xl md:text-5xl leading-tight ${className}`}>
      <div className="mt-4">
        <div className="flex flex-wrap gap-x-3 gap-y-2 dark:text-white text-black">
          {wordsArray.map((word, idx) => {
            const isVisible = idx < visibleCount;
            return (
              <span
                key={idx}
                style={{
                  opacity: isVisible ? 1 : 0,
                  filter: isVisible ? 'blur(0px)' : 'blur(4px)',
                  transform: isVisible ? 'translateY(0px)' : 'translateY(10px)',
                  transition: 'opacity 0.5s ease, filter 0.5s ease, transform 0.5s ease'
                }}
                className="inline-block"
              >
                {word}
              </span>
            );
          })}
        </div>
      </div>
    </div>
  );
}
